    10→import com.fasterxml.jackson.databind.ObjectMapper;
    11→import com.fasterxml.jackson.databind.module.SimpleModule;
    12→import com.grl.component.asg.AsgUtils;
    13→import io.swagger.v3.core.util.Yaml;
    14→import io.swagger.v3.oas.models.Components;
    15→import io.swagger.v3.oas.models.OpenAPI;
    16→import io.swagger.v3.oas.models.info.Info;
    17→import io.swagger.v3.oas.models.security.SecurityRequirement;
    18→import jakarta.validation.ConstraintViolation;
    19→import jakarta.validation.ConstraintViolationException;
    20→import jakarta.validation.Validation;
    21→import jakarta.validation.Validator;
    22→import java.io.IOException;
    23→import java.net.URI;
    24→import java.net.URISyntaxException;
    25→import java.net.URLDecoder;
    26→import java.nio.charset.Charset;
    27→import java.nio.file.Files;
    28→import java.nio.file.Path;
    29→import java.util.List;
    30→import java.util.Map;
    31→import java.util.Optional;
    32→import java.util.Set;
    33→import java.util.logging.Logger;
    34→import org.apache.commons.lang3.StringUtils;
    35→import org.apache.commons.text.StringSubstitutor;
    36→
    37→public class Config {
    38→
    39→  private final static Logger logger = Logger.getLogger(Config.class.getName());
    40→  private static final String BOILERPLATE_CONFIG = "/default.config.yaml";
    41→  static final private ObjectMapper yamlMapper = Yaml.mapper()
    42→      .setSerializationInclusion(Include.NON_NULL)
    43→      .enable(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES)
    44→      .addMixIn(OpenAPI.class, MergableOpenApi.class);
    45→  static final private Validator validator = Validation.buildDefaultValidatorFactory()
    46→      .getValidator();
    47→
    48→  public static YamlConfig loadInternal(Path configPath) throws IOException {
    49→
    50→    // Set up custom deserializer for Path and URI objects relative paths are resolved against the config file's
    51→    // location
    52→    ObjectMapper configMapper = yamlMapper.copy()
    53→        .registerModule(new SimpleModule().addDeserializer(Path.class, new JsonDeserializer<Path>() {
    54→          @Override
    55→          public Path deserialize(JsonParser jsonParser, DeserializationContext deserializationContext) throws IOException, JacksonException {
    56→            Path deserialized = yamlMapper.readValue(jsonParser, Path.class); // call default deserializer
    57→            return deserialized.isAbsolute() ? deserialized : configPath.getParent().resolve(deserialized).normalize();
    58→          }
    59→        }).addDeserializer(URI.class, new JsonDeserializer<URI>() {
    60→          @Override
    61→          public URI deserialize(JsonParser jsonParser, DeserializationContext ctxt) throws IOException,
    62→              JacksonException {
    63→            try {
    64→              // Note urldecode here as the URI ctor urlencodes and we risk a double encode if its stored urlencoded (which is traditional)
    65→              String deserializedAsString = URLDecoder.decode(
    66→                  yamlMapper.readValue(jsonParser, String.class),
    67→                  Charset.defaultCharset());
    68→              URI deserialized = new URI(null, deserializedAsString, null);
    69→              return StringUtils.isEmpty(deserialized.getScheme()) || "file".equals(deserialized.getScheme()) ?
    70→                  configPath.getParent()
    71→                  .resolve(deserialized.getSchemeSpecificPart()).normalize().toUri() : deserialized;
    72→            } catch (URISyntaxException e) {
    73→              throw new RuntimeException(e);
    74→            }
    75→          }
    76→        }));
    77→    // Crudely fix up 'variables' so we have use (e.g. ${configDir}) in the whole string content of the input file
    78→    Map<String, String> variables = Map.of("configDir", configPath.getParent().toAbsolutePath().toString());
    79→    String configAsString = new StringSubstitutor(variables).replace(Files.readString(configPath));
    80→    YamlConfig preParsedConfig = Optional.ofNullable(configMapper.readValue(configAsString, YamlConfig.class))
    81→        .orElseThrow();
    82→
    83→    YamlConfig extended = Optional.ofNullable(preParsedConfig.getExtends()).map(extendsConfig -> {
    84→      try {
    85→        return loadInternal(extendsConfig);
    86→      } catch (IOException e) {
    87→        throw new RuntimeException("Failed to read extended config file: " + extendsConfig, e);
    88→      }
    89→    }).orElse(configMapper.readValue(AsgUtils.class.getResourceAsStream(BOILERPLATE_CONFIG), YamlConfig.class));
    90→
    91→    // Read config again, merging over default boilerplate
    92→    return Optional.ofNullable(configMapper.readerForUpdating(extended).readValue(configAsString, YamlConfig.class))
    93→        .orElseThrow(() -> new RuntimeException("Config file is empty:" + configPath));
    94→  }
    95→
    96→  public static YamlConfig load(Path configPath) throws IOException {
    97→    YamlConfig config = loadInternal(configPath);
    98→    Set<ConstraintViolation<YamlConfig>> violations = validator.validate(config);
    99→    if (!violations.isEmpty()) {
   100→      violations.forEach(violation -> logger.severe(violation.getMessage() + ": " + violation.getInvalidValue()));
   101→      throw new ConstraintViolationException("Config file is invalid: ", violations);
   102→    } else {
   103→      return config;
   104→    }
   105→  }
   106→
   107→  /**
   108→   * Hacky interface to supply override annotations to Swagger-defined OpenAPI so we can easily merge properties
   109→   * between configs
   110→   */
   111→  interface MergableOpenApi {
   112→    @JsonMerge
   113→    Components getComponents();
   114→
   115→    @JsonMerge
   116→    Info getInfo();
   117→
   118→    @JsonMerge
   119→    io.swagger.v3.oas.models.Paths getPaths(); // this doesn't seem to work for Map-based property, though not needed at present, may be fixed by https://github.com/FasterXML/jackson-databind/issues/4922
   120→
   121→    @JsonMerge
   122→    List<SecurityRequirement> getSecurity();
   123→  }
   124→
   125→}
